var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"후후, 제법이군. 미스터 메이슨.","JPN":"ふふ、なかなかだな。ミスターメイソン。","ENG":"Haha! Not too shabby. Mr. Mason.","TWN":"呵呵，還真有兩下子啊，梅森先生。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"역시 이 토미 더 다이하드에 필적하는 용병이라고 할 만해.","JPN":"さすが、このトミー・ザ・ダイハードに匹敵する傭兵と言われるだけある。","ENG":"You're worthy of being called Tommy the Die-hard's rival.","TWN":"不愧是能和我頑強·湯米互相匹敵的傭兵。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"한때의 동료가 적이 되어 유감이군.","JPN":"かつての仲間が敵になって残念だ。","ENG":"Too bad you're our enemy now, old friend.","TWN":"昔日的同伴變成今日的敵人，真是令人遺憾啊。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"하지만 용병들끼리 이럴 때도 있는 거잖아. 하하, 이해해 줄 거지?","JPN":"だが同じ傭兵同士なんだ。ハハッ、こんな時もあるとわかってくれるよな？","ENG":"But that's bound to happen when you're mercenaries. Haha! I'm sure you understand, right?","TWN":"不過同為傭兵，總會有這樣的時候。哈哈，你會理解我的對吧？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"개인적인 감정은 없어.","JPN":"とくに個人的な恨みはないんだ。","ENG":"It's nothing personal.","TWN":"我對你沒什麼私人恩怨。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"항복한다면 거칠게 다루진 않을 테니까 잘 선택하라고.","JPN":"投降するなら手荒く扱うことはない。くれぐれも間違った選択はしないようにな。","ENG":"I'll go easy on you if you surrender, so you better choose wisely.","TWN":"只要你投降的話，我就不會對你太粗暴。你自己想想該怎麼做吧。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......후우, 머리가 아파오는군.","JPN":"……ふう、頭が痛くなってきた。","ENG":"Ugh... This is giving me a headache.","TWN":"……唉，我頭開始痛了。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"저 삼인방은 누구야? 아저씨랑 아는 사이야?","JPN":"あの3人組は誰？　おじさんの知り合い？","ENG":"Who are those three stooges? Friends of yours?","TWN":"這三人組是誰啊？大叔你認識他們嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"딱히 알고 말고 할 만한 사이도 아니야.","JPN":"知り合いと言えるほどの仲でもない。","ENG":"Let's just call them acquaintances...","TWN":"也不是什麼特別認識的關係。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"예전에 딱 한 번 같이 작전을 나갔던 적이 있지. 그뿐이다.","JPN":"以前、たった一度だけ同じ作戦に同行したことがあるんだ。それだけの話だ。","ENG":"We went on one mission together. That's it.","TWN":"就是以前有一次和他們一起作戰，僅此而已。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......내 이름을 기억하고 있다는 게 더 신기하군.","JPN":"……俺の名前を覚えているのが何より驚きだな。","ENG":"I'm surprised they even remember my name...","TWN":"……沒想到他們還記得我的名字。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 자네들.","JPN":"おい、お前ら。","ENG":"Hey, guys.","TWN":"喂，你們幾個。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"늦게 도착해서 상황을 잘 모르는 모양인데, 다른 현상금 사냥꾼 떨거지들은 모조리 박살나서 흩어졌다고.","JPN":"一歩遅れたせいで状況が読めてないようだが、他の賞金稼ぎの奴らは木っ端みじんになって去っていったぞ。","ENG":"You're a bit late to the party, but all the other bounty hunters ran off because I beat them 'til they cried.","TWN":"我看你們來晚了，好像還搞不太清楚狀況的樣子。其他賞金獵人全都被打得落花流水，落荒而逃了。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"거기다 이쪽은 카운터 포함 여섯 명이고 너희들은 달랑 세 명이야.","JPN":"しかも、こっちはカウンター含めて6人なのに、お前らはたったの3人。","ENG":"There's six of us including these Counters, and there's only three of you.","TWN":"然後我們這裡包括制裁者一共有六人，但你們只有孤零零的三個人。"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 정말 해볼 생각인가?","JPN":"本気で戦う気か？","ENG":"Are you sure you wanna do this?","TWN":"這種情況下，你們還想要來試試看嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭐, 뭣?!","JPN":"な、なに！？","ENG":"Wh-what?!","TWN":"什、什麼？！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"야! 제리! 카운터 포함이라니 그런 말은 없었잖아?!","JPN":"おい！　ジェリー！　カウンターがいるとは言ってなかったじゃないか！？","ENG":"Hey! Jerry! No one told us about any Counters!","TWN":"喂！傑瑞！我可沒聽說有制裁者啊？！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭔 소리야? 수배서에 분명히 적혀 있었잖아?!","JPN":"はあ？　何言ってんだ？　指名手配書にハッキリと書いてあるぜ？","ENG":"What? It was written on the wanted list!","TWN":"你在說什麼啊？通緝令上不是清清楚楚寫著嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};